mapper.sql:
SELECT
ID

PQ_NO

CARGO_NAME

YARD_NAME

QUANTITY

TON

IN_PORT_TIME

IN_PORT_NAME

OUT_PORT_TIME

OUT_PORT_NAME

STATUS

IN_SHIP_NAME

IN_VOYAGE

OUT_SHIP_NAME

OUT_VOYAGE

DEL_FLAG

CREATE_BY

CREATE_BY_NAME

CREATE_TIME

UPDATE_BY

UPDATE_BY_NAME

UPDATE_TIME

FROM
T_HQ_DATA


        and ID = #{id}


        and PQ_NO = #{pqNo}


        and CARGO_NAME = #{cargoName}


        and YARD_NAME = #{yardName}


        and QUANTITY = #{quantity}


        and TON = #{ton}


        and IN_PORT_TIME = #{inPortTime}


        and IN_PORT_NAME = #{inPortName}


        and OUT_PORT_TIME = #{outPortTime}


        and OUT_PORT_NAME = #{outPortName}


        and STATUS = #{status}


        and IN_SHIP_NAME = #{inShipName}


        and IN_VOYAGE = #{inVoyage}


        and OUT_SHIP_NAME = #{outShipName}


        and OUT_VOYAGE = #{outVoyage}


        and DEL_FLAG = #{delFlag}

mapper.select:
SELECT id "id", PQ_NO "pqNo", MAX(YARD_NAME) "yardName", REGEXP_REPLACE( LISTAGG(STACK_POSITION_NAME, ', ') WITHIN GROUP (ORDER BY STACK_POSITION_NAME), '([^,]+)(,\1)+', '\1' ) "stackPositionName", REGEXP_REPLACE( LISTAGG(CARGO_NAME, ', ') WITHIN GROUP (ORDER BY CARGO_NAME), '([^,]+)(,\1)+', '\1' ) "cargoName" FROM ( SELECT DISTINCT thd.id, thd.PQ_NO, tyti.STACK_POSITION_NAME, thd.YARD_NAME, thd.CARGO_NAME FROM T_HQ_DATA thd, T_HQ_TALLY tht, T_YARD_TALLY tyt, T_YARD_TALLY_ITEM tyti WHERE thd.ID = THT.HQ_DATA_ID(+) AND tht.TALLY_ID = tyt.ID(+) AND tyt.ID = tyti.TALLY_ID(+) AND thd.STATUS = '10' AND thd.DEL_FLAG != '0' AND THT.TALLY_ID = tyt.ID
#{id}
) GROUP BY id,PQ_NO

mapper.insert:
INSERT INTO T_HQ_DATA( ID, PQ_NO, HQ_CARGO_ID, CARGO_NAME, HQ_YARD_ID, YARD_NAME, QUANTITY, TON, HQ_LENGTH, WIDTH, HEIGHT, VOLUME, IN_PORT_TIME, IN_PORT_NAME, OUT_PORT_TIME, OUT_PORT_NAME, STATUS, IN_SHIP_NAME, IN_VOYAGE, OUT_SHIP_NAME, OUT_VOYAGE, DEL_FLAG, CREATE_BY, CREATE_BY_NAME, CREATE_TIME) (
SELECT #{item.id}, #{item.pqNo, jdbcType=VARCHAR}, #{item.hqCargoId}, #{item.cargoName, jdbcType=VARCHAR}, #{item.hqYardId}, #{item.yardName, jdbcType=VARCHAR}, #{item.quantity, jdbcType=VARCHAR}, #{item.ton, jdbcType=VARCHAR}, #{item.hqLength, jdbcType=VARCHAR}, #{item.width, jdbcType=VARCHAR}, #{item.height, jdbcType=VARCHAR}, #{item.volume, jdbcType=VARCHAR}, #{item.inPortTime, jdbcType=VARCHAR}, #{item.inPortName, jdbcType=VARCHAR}, #{item.outPortTime, jdbcType=VARCHAR}, #{item.outPortName, jdbcType=VARCHAR}, #{item.status, jdbcType=VARCHAR}, #{item.inShipName, jdbcType=VARCHAR}, #{item.inVoyage, jdbcType=VARCHAR}, #{item.outShipName, jdbcType=VARCHAR}, #{item.outVoyage, jdbcType=VARCHAR}, #{item.delFlag, jdbcType=VARCHAR}, #{item.loginUserId, jdbcType=BIGINT}, #{item.loginUserName, jdbcType=VARCHAR}, #{item.now} from dual
)

mapper.select:
SELECT ID, PQ_NO, HQ_CARGO_ID, CARGO_NAME, HQ_YARD_ID, YARD_NAME, QUANTITY, TON, HQ_LENGTH, WIDTH, HEIGHT, VOLUME, IN_PORT_TIME, IN_PORT_NAME, OUT_PORT_TIME, OUT_PORT_NAME, STATUS, IN_SHIP_NAME, IN_VOYAGE, IN_SHIP_NAME || '_' || IN_VOYAGE "inShipVoyage", OUT_SHIP_NAME, OUT_VOYAGE, OUT_SHIP_NAME || '_' || OUT_VOYAGE "outShipVoyage", DEL_FLAG, CREATE_BY, CREATE_BY_NAME, CREATE_TIME, UPDATE_BY, UPDATE_BY_NAME, UPDATE_TIME FROM T_HQ_DATA
id in
#{id}

mapper.update:
begin
UPDATE T_HQ_DATA
PQ_NO = #{item.pqNo,jdbcType=VARCHAR}, HQ_CARGO_ID = #{item.hqCargoId}, CARGO_NAME = #{item.cargoName,jdbcType=VARCHAR}, HQ_YARD_ID = #{item.hqYardId}, YARD_NAME = #{item.yardName,jdbcType=VARCHAR}, QUANTITY = #{item.quantity,jdbcType=VARCHAR}, TON = #{item.ton,jdbcType=VARCHAR}, HQ_LENGTH = #{item.hqLength, jdbcType=VARCHAR}, WIDTH = #{item.width, jdbcType=VARCHAR}, HEIGHT = #{item.height, jdbcType=VARCHAR}, VOLUME = #{item.volume, jdbcType=VARCHAR}, IN_PORT_TIME = #{item.inPortTime,jdbcType=VARCHAR}, IN_PORT_NAME = #{item.inPortName,jdbcType=VARCHAR}, OUT_PORT_TIME = #{item.outPortTime,jdbcType=VARCHAR}, OUT_PORT_NAME = #{item.outPortName,jdbcType=VARCHAR}, STATUS = #{item.status,jdbcType=VARCHAR}, IN_SHIP_NAME = #{item.inShipName,jdbcType=VARCHAR}, IN_VOYAGE = #{item.inVoyage,jdbcType=VARCHAR}, OUT_SHIP_NAME = #{item.outShipName,jdbcType=VARCHAR}, OUT_VOYAGE = #{item.outVoyage,jdbcType=VARCHAR}, DEL_FLAG = #{item.delFlag,jdbcType=VARCHAR}, UPDATE_BY = #{item.loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{item.loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{item.now}
WHERE ID = #{item.id, jdbcType=BIGINT};
end;

delete.foreach:
UPDATE T_HQ_DATA
OUT_VOYAGE = null, OUT_SHIP_NAME = null, OUT_PORT_NAME = null, OUT_PORT_TIME = null,
DEL_FLAG = #{item.delFlag}, STATUS = #{item.status}
id = #{item.id}
